          // Treat trivially constant branch conditions as extra simplification,
          // even if the legacy cost model would skip costing them. For example:
          //   br i1 (trunc (or %x, C) to i1), ...
          // where C has its least significant bit set, making the condition true.
          if (auto *Br = dyn_cast<BranchInst>(&I)) {
            if (Br->isConditional()) {
