              auto LSBSet = [](Value *V) {
                if (auto *CI = dyn_cast<ConstantInt>(V))
                  return CI->getBitWidth() > 0 && (CI->getZExtValue() & 1ULL);
                return false;
              };
              if (auto *Tr = dyn_cast<TruncInst>(Cond)) {
